    alm_dest_a = "Todos"

    # Segunda fila de filtros: origen y destino en cascada
    col_f4, col_f5 = st.columns([1.5, 1.5])

    with col_f4:
        alm_origen_opts = ["Todos"] + sorted(df["De código de almacén"].dropna().unique().tolist(), key=str)
